": ["contradiction_free", "unsupported_claims_absent", "fulfillment_assessment_coverage"], "reason": "always", "retry_count": 0, "stop_reason": "", "to_state": "finalize"}, {"condition": "stop", "from_state": "finalize", "gate_ids": ["finalization_ready", "contradiction_free", "unsupported_claims_absent"], "reason": "stop", "retry_count": 0, "stop_reason": "completed", "to_state": "completed"}], "verdict": "correct", "verdict_derivation": {"condition_comparison_actual": {"query_logic": "AND"}, "condition_comparison_expected": {"expected_source": "not_available", "query_logic": "AND", "reference_is_oracle": false}, "core_reasoning": "actual output 满足所有四项业务期望：口语映射正确（重疾险→疾病保险）、字段选择正确（pCategorys）、操作符在边界规则下等价可执行（MATCH 等价于 CONTAINS）、条件覆盖完整无冗余。下游搜索不可用，但在此 judge_scope 下基于 parser 条件语义即可做出正确性判断。", "missing_evidence": ["current intent/config expected conditions"], "why_verdict": "client_search condition comparison has no current intent/config expected conditions; reference conditions are evidence only"}, "wrong_missing_extra": {}}, "project_extensions": {"display_contract": {"formatting": ["json formatting", "truncation", "output/reference alignment"], "output_source": "trace.live_result.extracted_output", "reference_source": "judge_generated"}, "frontend_standard": {"batch_persistence": {"case_shape": "id, selected, input, output, reference, metadata, scenario, source, status, error", "transient_results": "do not persist full trace, judge, attribute, downstream payload, or frontend_view as durable case-pool source data"}, "frontend_view": {"live": "render normalized parser output and raw project fields under protocol extension panels", "summary": "align Output and Reference as formatted JSON with equal-size table cells and compact drill-downs"}}, "verifiable_tools": {"available": true, "catalog": [{"applicable_scenario": "attr", "description": "调业务搜索解析接口，传入自然语言查询，返回解析出的搜索条件、匹配级别、匹配模式。用于验证业务系统当前行为是否和 trace 记录一致。", "has_execute_fn": true, "parameters": {"properties": {"query": {"description": "自然语言搜索查询，如'\''45岁女性保费10万以上'\''", "type": "string"}, "user_id": {"description": "用户ID，默认 eval-verifier", "type": "string"}}, "required": ["query"], "type": "object"}, "tool_id": "client_search.search_api"}, {"applicable_scenario": "attr", "description": "查询业务字段的能力定义：允许的操作符、值类型、枚举值、单位。用于验证 trace actual 里的 field/operator/value 是否在字段能力范围内（actual 交叉对照）。", "has_execute_fn": true, "parameters": {"properties": {"field": {"description": "字段名，如 clientAge、annPremSegNum、pCategorys", "type": "string"}}, "required": ["field"], "type": "object"}, "tool_id": "client_search.field_capability"}, {"applicable_scenario": "attr", "description": "验证配置映射规则生效情况：给定关键词/字段，返回 value_mappings 和 enhanced_rules 中匹配的实际配置内容。用于判断业务系统的规则是否被正确触发（actual 交叉对照）。", "has_execute_fn": true, "parameters": {"properties": {"field": {"description": "字段名（同 keyword），用于过滤映射规则", "type": "string"}, "keyword": {"description": "关键词或字段名，用于过滤映射规则。如'\''年金'\''、'\''premium'\''、'\''clientAge'\''", "type": "string"}}, "type": "object"}, "tool_id": "client_search.rule_verify"}, {"applicable_scenario": "attr", "description": "API endpoint: GET / (root) — 根路径", "has_execute_fn": true, "parameters": {"type": "object"}, "tool_id": "client_search.api.root"}, {"applicable_scenario": "attr", "description": "API endpoint: GET /health (health_check) — 健康检查", "has_execute_fn": true, "parameters": {"type": "object"}, "tool_id": "client_search.api.health_check"}, {"applicable_scenario": "attr", "description": "API endpoint: POST /api/v1/client_search_query_parse (client_search_query_parse) — 解析自然语言查询，返回结构化条件和逻辑关系，不执行实际搜索。\n遵循 AskBob 标准 Bot 接入协议，入参和出参均为标准包装格式。", "has_execute_fn": true, "parameters": {"properties": {"body": {"description": "请求体 JSON", "type": "object"}, "request": {"description": "参数 request", "type": "string"}}, "required": ["request"], "type": "object"}, "tool_id": "client_search.api.client_search_query_parse"}, {"applicable_scenario": "attr", "description": "API endpoint: POST /api/v1/client_search_query_parse_no_encipher (client_search_query_parse_no_encipher) — 解析自然语言查询，返回结构化条件和逻辑关系，不执行实际搜索。\n遵循 AskBob 标准 Bot 接入协议，入参和出参均为标准包装格式。", "has_execute_fn": true, "parameters": {"properties": {"body": {"description": "请求体 JSON", "type": "object"}, "request": {"description": "参数 request", "type": "string"}}, "required": ["request"], "type": "object"}, "tool_id": "client_search.api.client_search_query_parse_no_encipher"}, {"applicable_scenario": "attr", "description": "API endpoint: POST /api/v1/fields/retrieve (retrieve_fields) — RAG 字段检索接口\n\n根据自然语言查询，从知识库中召回最相关的字段意图，\n返回字段定义及可直接注入 LLM Prompt 的文本段落。\n\nArgs:\n    request: 包含 query（查询文本）和 top_k（返回数量）\n\nReturns:\n    匹配的字段意图列表及格式化的 prompt 片段", "has_execute_fn": true, "parameters": {"properties": {"body": {"description": "请求体 JSON", "type": "object"}, "request": {"description": "参数 request", "type": "string"}}, "required": ["request"], "type": "object"}, "tool_id": "client_search.api.retrieve_fields"}]}}, "project_info": {"description": "将客户搜索项目作为通用评估系统的第一个项目适配实现。", "name": "客户搜索评估示例", "project_id": "client_search"}, "reference_panel": {"actual": {"code": 0, "conditions": [{"field": "pCategorys", "operator": "MATCH", "value": "疾病保险"}], "confidence": 0.8, "cost_times": 1101.0, "end_flag": 1, "intent_summary": "产品类别为疾病保险的客户", "matched_level": 4, "matched_patterns": "### 当前时间\n2026-07-07 13:31:59 (Asia/Shanghai)\n### 今天星期\n周二\n\n### 相关字段参考（根据查询内容动态召回）\n\n\n- **isBuyInsurance** | 操作符: CONTAINS | 值类型: enum | 枚举: ['\''客户'\'', '\''准客'\'', '\''用户'\''] | 定义: 客户类型；客户/准客=买过保险，用户=没有买过保险 | 说明: 客户=已签约，准客=潜在客户已接触，用户=未购买；买过保险→客户或准客，没有买过保险→用户\n\n  示例: \"有保险的客户\" → {\"field\": \"isBuyInsurance\", \"operator\": \"CONTAINS\", \"value\": [\"客户\", \"准客\"]}\n\n  示例: \"没有保险的客户\" → {\"field\": \"isBuyInsurance\", \"operator\": \"CONTAINS\", \"value\": [\"用户\"]}\n\n- **searchClientName** | 操作符: MATCH | 值类型: extract | 定义: 表示客户本人完整姓名，不表示家庭成员、被保人、投保人姓名 | 说明: 当查询直接出现完整中文姓名时，必须保留全名原样输出；如\"陈成\"\"李保\"\"张无\"\"金美\"应输出完整姓名，不能截断为\"陈\"\"李\"\"张\"\"金\"，也不能因为名字较少见而